import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";
import * as radix from "@radix-ui/colors";

import {
  admonitionTypes,
  outputPath,
  scaleOrder,
  schemeSettings,
  sharedRules,
} from "./radix-theme-config.mjs";

const header = `/*
 * Generated by scripts/generate-radix-css.mjs.
 * Do not edit this file directly.
 *
 * Zensical theme variables are generated from Radix color scales.
 * Semantic mappings mirror the design choices in:
 * - quarto-ref/html/_colors-light.scss
 * - quarto-ref/html/_colors-dark.scss
 * Base scale values come from @radix-ui/colors.
 */
`;

function renderDeclarations(entries) {
  return entries.map(([name, value]) => `  ${name}: ${value};`).join("\n");
}

function scaleFor(name, mode) {
  const exportName = mode === "dark" ? `${name}Dark` : name;
  const scale = radix[exportName];

  if (!scale) {
    throw new Error(`Missing Radix color export: ${exportName}`);
  }

  return scale;
}

function renderScaleVariables(mode) {
  const declarations = [];

  for (const scaleName of scaleOrder) {
    const scale = scaleFor(scaleName, mode);

    declarations.push(`  /* ${scaleName} */`);

    for (let step = 1; step <= 12; step += 1) {
      declarations.push(`  --rx-${scaleName}-${step}: ${scale[`${scaleName}${step}`]};`);
    }

    declarations.push("");
  }

  return declarations.join("\n").trimEnd();
}

function renderSchemeBlock(name, mode) {
  const { colorScheme, themeVars, zensicalVars } = schemeSettings[name];
  const sections = [
    `[data-md-color-scheme="${name}"] {`,
    `  color-scheme: ${colorScheme};`,
    "",
    renderScaleVariables(mode),
    "",
    "  /* Semantic tokens */",
    renderDeclarations(themeVars),
    "",
    "  /* Zensical theme variables */",
    renderDeclarations(zensicalVars),
    "}",
  ];

  return sections.join("\n");
}

function renderRule(selector, declarations) {
  return `${selector} {\n${renderDeclarations(declarations)}\n}`;
}

function renderAdmonitionRule(type, scaleName) {
  const color = `var(--rx-${scaleName}-9)`;
  const titleBackground = `color-mix(in srgb, ${color} 14%, transparent)`;
  const selectors = [
    `[data-md-color-scheme^="radix-"] .md-typeset .admonition.${type}`,
    `[data-md-color-scheme^="radix-"] .md-typeset details.${type}`,
  ].join(",\n");
  const titleSelectors = [
    `[data-md-color-scheme^="radix-"] .md-typeset .${type} > .admonition-title`,
    `[data-md-color-scheme^="radix-"] .md-typeset .${type} > summary`,
  ].join(",\n");
  const iconSelectors = [
    `[data-md-color-scheme^="radix-"] .md-typeset .${type} > .admonition-title::before`,
    `[data-md-color-scheme^="radix-"] .md-typeset .${type} > summary::before`,
  ].join(",\n");

  return [
    renderRule(selectors, [["border-color", color]]),
    renderRule(titleSelectors, [["background-color", titleBackground]]),
    renderRule(iconSelectors, [["background-color", color]]),
  ].join("\n\n");
}

const content = [
  header.trimEnd(),
  "",
  renderSchemeBlock("radix-light", "light"),
  "",
  renderSchemeBlock("radix-dark", "dark"),
  "",
  ...sharedRules.map(([selector, declarations]) => renderRule(selector, declarations)),
  "",
  ...admonitionTypes.map(([type, scaleName]) => renderAdmonitionRule(type, scaleName)),
  "",
]
  .join("\n")
  .trimEnd()
  .concat("\n");

const resolvedOutputPath = path.resolve(outputPath);
await mkdir(path.dirname(resolvedOutputPath), { recursive: true });
await writeFile(resolvedOutputPath, content);
